final:
module RefModule (
    input clk,
    input rst,
    output reg [2:0] gray
);
    reg [2:0] obf_binary;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_binary <= 3'b000;
        else
            obf_binary <= obf_binary + 1;
    end

    always @(obf_binary) begin
        gray = obf_binary ^ (obf_binary >> 1);
    end
endmodule
